var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"네, 블랙 네트워크 쪽의 정보를 해킹한 기록이 그대로 남아 있어요.","JPN":"はい、ブラックネットワークの情報をハッキングした\\n記録がそのまま残っています。","ENG":"Yes, there's a record of them hacking into the Dark Network.","TWN":"是，發現了黑色網路上的資訊被入侵的記錄。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"이렇게 뒤처리를 안 하고 흔적을 남기는 부류는 둘 중 하나죠. 멍청하거나, 겁이 없거나.","JPN":"こんな風に痕跡を残すやつは二択ですね。\\nただの間抜けか、怖いもの知らずか。","ENG":"People who don't bother to clean after themselves are either too stupid or too bold.","TWN":"留下如此明顯痕跡的人能分為兩種，要麼是蠢貨，要麼不怕死。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"구출도 구출이지만, 맡긴 물건도 제대로 전해주도록 하세요.","JPN":"救出はもちろんですが、預けたものもきちんと\\n届けるように伝えてくださいね。","ENG":"While you're there to rescue Titan, also make sure that the item is safely delivered.","TWN":"除了救援之外，別忘了安全地轉交委託的東西。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사장님이 특별히 지시한 사항입니다.","JPN":"社長からの特命案件です。","ENG":"The Boss was very specific about that.","TWN":"這是老闆的特別指示。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......걱정 마세요. 두 임무 모두 확실히 해내겠습니다.","JPN":"……ご安心ください。両方とも確実にやり遂げます。","ENG":"Don't worry. We'll take care of both.","TWN":"……放心，兩個任務我都會完美完成的。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"서윤 양은 언제나 믿음직하군요.","JPN":"シズカさんはいつも頼もしいわね。","ENG":"Seo Yoon, you're so reliable, as always.","TWN":"徐芸小姐總是這麼可靠。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이젠 정식 라이선스도 얻었으니 이전처럼 <color=#ffd34c>돌발상황에 따른 불가피한 현장대응</color> 같은 일은 없을 거라 기대하겠습니다.","JPN":"正式ライセンスも取得したことですし、今後は\\n<color=#ffd34c>突発的な事情による、やむを得ない現場対応</color>などは発生しないことを\\n期待しているわ。","ENG":"Now that you've acquired the official license, I expect there will be no more <color=#ffd34c>spontaneous actions to address emergency situations</color> like the last time.","TWN":"既然獲得了正式執照，希望不會出現像上次那樣的<color=#ffd34c>因突發情況而不可避免的現場對應</color>。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그럼요. 믿음과 신뢰가 바로 저의 모토잖아요?","JPN":"もちろんです、安心と信頼が私のモットーですから。","ENG":"Of course. Trust and credibility are my motto.","TWN":"當然，我的座右銘就是信任與信賴嘛。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"잘 아시면서. 호호호.","JPN":"よくご存じのはずなのに、今さら水くさいですわ。オホホホ。","ENG":"You know that. Hah hah hah.","TWN":"您不是知道嘛，嘻嘻嘻。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그다지 잘 모르겠군요. 후후후......","JPN":"初耳な気がするのはなぜかしらね。ウフフフ……","ENG":"I don't think I do. Hah hah hah.","TWN":"我不是很懂喔，呵呵呵……"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그럼 다녀오겠습니다, 부사장님.","JPN":"では、行ってきます、副社長。","ENG":"Well, if you'll excuse me, Vice President.","TWN":"那我走了，副總。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"오랜만의 작전이잖아! 두근거리는 걸, 대장!","JPN":"久々の作戦！　わくわくするな、隊長！","ENG":"We're on a mission after so long. I'm so excited, Cap!","TWN":"很久沒有參加作戰了！好興奮，隊長！"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"이번 작전의 주 목표가 요인 구출이라는 걸 알긴 아는 거야?","JPN":"作戦の主な目標は要人救出ってこと、わかってるの？","ENG":"Do you even know the main objective of this mission is VIP recovery?","TWN":"你沒有忘記本次作戰的主要目的是救援吧？"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"괜히 날뛰다가 사고 쳐서 어렵게 받은 라이선스 박탈이나 당하지 말라고, 멍청아.","JPN":"むやみに暴れて何かやらかしたら、貴重なライセンスを\\n剥奪されるのよ。慎んでなさい、この脳筋イノシシ。","ENG":"You'd better not cause trouble. I don't want to lose our hard-earned license because of you.","TWN":"別惹事，若是闖禍會被剝奪執照的，笨蛋。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"내가 사고를 친다면 지금 당장일 것 같은데 어때? 앙!","JPN":"はぁ？　暴れるんだったら、今この瞬間が最高だと\\n思わねえか？　ああん！？","ENG":"How about I cause trouble right now? FOR YOU!","TWN":"信不信我現在就闖禍給你看？啊！"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"얘, 얘들아 진정해......","JPN":"み、みんな、落ち着いてよ……","ENG":"G-guys, calm down...","TWN":"你、你們不要鬧了。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"그보다 대장, 구출 대상이 그...... 정말이야?","JPN":"それより隊長。救出対象は、あの……本当なの？","ENG":"By the way, Cap. Is that VIP, erm, really...","TWN":"隊長，那個救援對象……是真的嗎？"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"하하, 그렇다는데? 사장님 딸이래.","JPN":"ハハ、そうらしいわよ？　社長の娘さんなんだって。","ENG":"Hah hah, yes. The Boss's daughter.","TWN":"哈哈，好像是的？是老闆的女兒。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};